class FeedbackType(Enum):
    """Types of user feedback for RAG learning"""
    POSITIVE_CONFIRMATION = "positive_confirmation"    # "thanks", "correct", "exactly"
    NEGATIVE_DENIAL = "negative_denial"               # "no", "wrong", "incorrect"
    EVIDENCE_REQUEST = "evidence_request"             # "show evidence", "prove it", "source?"
    CLARIFICATION_REQUEST = "clarification_request"   # "explain", "how?", "why?"
    ACCURACY_CHALLENGE = "accuracy_challenge"         # "are you sure?", "doubt that"
    TOOL_FEEDBACK = "tool_feedback"                   # "wrong tool", "use X instead"
    SUGGESTION_ACCEPTANCE = "suggestion_acceptance"   # "good idea", "let's do that"
    SUGGESTION_REJECTION = "suggestion_rejection"     # "no don't", "bad idea"

@dataclass
class FeedbackEntry:
    """Single feedback entry for learning"""
    timestamp: float
    user_input: str
    feedback_type: FeedbackType
    confidence: float
    context_window: List[str]  # Previous 3-5 interactions
    rag_active: bool
    tools_used: List[str]
    response_quality_score: float = 0.0
    learned_patterns: List[str] = field(default_factory=list)

@dataclass
class RAGPerformanceMetrics:
    """RAG performance tracking"""
    total_interactions: int = 0
    rag_active_interactions: int = 0
    positive_feedback_count: int = 0
    negative_feedback_count: int = 0
    evidence_requests: int = 0
    accuracy_challenges: int = 0
    tool_feedback_count: int = 0
    overall_satisfaction_score: float = 0.0
    response_accuracy_trend: List[float] = field(default_factory=list)

class RAGFeedbackEngine:
    """Engine for learning from user feedback to improve RAG accuracy"""

    def __init__(self):
        self.feedback_history = deque(maxlen=1000)
        self.performance_metrics = RAGPerformanceMetrics()
        self.interaction_context = deque(maxlen=10)  # Keep last 10 interactions

        # Feedback pattern recognition
        self.feedback_patterns = self._initialize_feedback_patterns()

        # Phase Sub-Zero-C: Log initialization
        if _debug_logger:
            _debug_logger.info("RAGFeedbackEngine initialized")

        # Learning weights for different feedback types
        self.learning_weights = {
            FeedbackType.POSITIVE_CONFIRMATION: 1.0,
            FeedbackType.NEGATIVE_DENIAL: -1.5,  # Stronger learning from mistakes
            FeedbackType.EVIDENCE_REQUEST: -0.8,  # Indicates unsupported claims
            FeedbackType.ACCURACY_CHALLENGE: -1.2,  # Questions our confidence
            FeedbackType.TOOL_FEEDBACK: -1.0,  # Tool selection issues
            FeedbackType.SUGGESTION_REJECTION: -0.6,
            FeedbackType.SUGGESTION_ACCEPTANCE: 0.8,
            FeedbackType.CLARIFICATION_REQUEST: -0.3,  # Slight negative, unclear response
        }

        # RAG optimization insights
        self.rag_insights = {
            'high_confidence_errors': [],    # Times we were wrong with high confidence
            'evidence_gaps': [],             # Claims that needed evidence
            'tool_mismatches': [],           # Wrong tool selections
            'clarity_issues': [],            # Responses needing clarification
        }

    def _initialize_feedback_patterns(self) -> Dict[FeedbackType, List[str]]:
        """Initialize patterns for recognizing different types of feedback"""

        return {
            FeedbackType.POSITIVE_CONFIRMATION: [
                r'^(thanks?|thank you|ty|thx)\s*!?$',
                r'^(correct|right|exactly|perfect|yes|yeah|yep)\s*!?$',
                r'^(good|great|nice|excellent|awesome)\s*!?$',
                r'^that\'?s (right|correct|perfect|good)$',
                r'^(works?|working|fixed|solved)!?$',
                r'^(helpful|useful|good answer)$',
            ],

            FeedbackType.NEGATIVE_DENIAL: [
                r'^(no|nope|wrong|incorrect|false|bad)\s*!?$',
                r'^that\'?s (wrong|incorrect|false|not right)$',
                r'^(not correct|not right|doesn\'t work)$',
                r'^(failed|error|broken|doesn\'t help)$',
                r'^i disagree',
                r'^(not what i meant|not what i asked)',
            ],

            FeedbackType.EVIDENCE_REQUEST: [
                r'(show|provide|give).+(evidence|proof|source)',
                r'(where|what).+(source|reference)',
                r'(prove it|show me|evidence|source)',
                r'(how do you know|based on what)',
                r'(citation|reference|link)',
                r'(verify|confirm).+(that|this)',
            ],

            FeedbackType.ACCURACY_CHALLENGE: [
                r'(are you sure|certain|confident)',
                r'(doubt|question|suspicious).+(that|this)',
                r'i (think|believe|suspect).+wrong',
                r'(double.?check|verify|confirm).+(this|that)',
                r'(seems wrong|doesn\'t sound right)',
                r'(really\?|seriously\?|honestly\?)',
            ],

            FeedbackType.CLARIFICATION_REQUEST: [
                r'^(explain|clarify|elaborate)',
                r'^(what do you mean|how so|why)',
                r'^(can you explain|tell me more)',
                r'^(i don\'t understand|unclear|confusing)',
                r'^(rephrase|say that again)',
                r'^(more details?|be more specific)',
            ],

            FeedbackType.TOOL_FEEDBACK: [
                r'(wrong tool|use .+ instead)',
                r'(should have used|try using)\s+\w+',
                r'(not the right tool|incorrect tool)',
                r'^(use|try)\s+\w+\s+(instead|tool)$',
                r'(tool selection|different tool)',
            ],

            FeedbackType.SUGGESTION_ACCEPTANCE: [
                r'^(good idea|great suggestion|let\'s do that)',
                r'^(sounds good|i like that|perfect)',
                r'^(go ahead|proceed|do it)',
                r'^(that works|that\'s fine|agreed?)',
                r'^(yes.*(suggestion|idea|plan))',
            ],

            FeedbackType.SUGGESTION_REJECTION: [
                r'^(bad idea|don\'t do that|no don\'t)',
                r'^(not good|not right|won\'t work)',
                r'^(different approach|try something else)',
                r'^(no.*(suggestion|idea|plan))',
                r'^(reject|refuse|decline)',
            ],
        }

    def analyze_user_feedback(self, user_input: str, context: Dict[str, Any]) -> Optional[FeedbackEntry]:
        """Analyze user input for feedback signals"""

        # Detect feedback type
        feedback_type = self._classify_feedback(user_input)
        if not feedback_type:
            return None

        # Calculate confidence in feedback classification
        confidence = self._calculate_feedback_confidence(user_input, feedback_type)

        # Create feedback entry
        feedback_entry = FeedbackEntry(
            timestamp=time.time(),
            user_input=user_input.strip(),
            feedback_type=feedback_type,
            confidence=confidence,
            context_window=list(self.interaction_context)[-5:],
            rag_active=context.get('rag_active', False),
            tools_used=context.get('tools_used', [])
        )

        # Record the feedback
        self._record_feedback(feedback_entry)

        return feedback_entry

    def _classify_feedback(self, user_input: str) -> Optional[FeedbackType]:
        """Classify user input into feedback type"""

        text = user_input.lower().strip()

        # Try each feedback type's patterns
        for feedback_type, patterns in self.feedback_patterns.items():
            for pattern in patterns:
                if re.search(pattern, text):
                    return feedback_type

        return None

    def _calculate_feedback_confidence(self, user_input: str, feedback_type: FeedbackType) -> float:
        """Calculate confidence in feedback classification"""

        text = user_input.lower().strip()
        base_confidence = 0.7

        # High confidence patterns
        high_confidence_indicators = {
            FeedbackType.POSITIVE_CONFIRMATION: ['thanks', 'correct', 'perfect'],
            FeedbackType.NEGATIVE_DENIAL: ['wrong', 'incorrect', 'false'],
            FeedbackType.EVIDENCE_REQUEST: ['source', 'prove', 'evidence'],
            FeedbackType.ACCURACY_CHALLENGE: ['are you sure', 'doubt', 'really?'],
        }

        if feedback_type in high_confidence_indicators:
            for indicator in high_confidence_indicators[feedback_type]:
                if indicator in text:
                    base_confidence = min(0.95, base_confidence + 0.15)

        # Adjust for text length and specificity
        word_count = len(text.split())
        if word_count == 1:
            base_confidence += 0.1  # Simple responses are often clear
        elif word_count > 10:
            base_confidence -= 0.1  # Complex responses might be ambiguous

        return base_confidence

    def _record_feedback(self, feedback_entry: FeedbackEntry):
        """Record feedback and update performance metrics"""

        self.feedback_history.append(feedback_entry)

        # Update performance metrics
        self.performance_metrics.total_interactions += 1

        if feedback_entry.rag_active:
            self.performance_metrics.rag_active_interactions += 1

        if feedback_entry.feedback_type == FeedbackType.POSITIVE_CONFIRMATION:
            self.performance_metrics.positive_feedback_count += 1
        elif feedback_entry.feedback_type == FeedbackType.NEGATIVE_DENIAL:
            self.performance_metrics.negative_feedback_count += 1
        elif feedback_entry.feedback_type == FeedbackType.EVIDENCE_REQUEST:
            self.performance_metrics.evidence_requests += 1
        elif feedback_entry.feedback_type == FeedbackType.ACCURACY_CHALLENGE:
            self.performance_metrics.accuracy_challenges += 1
        elif feedback_entry.feedback_type == FeedbackType.TOOL_FEEDBACK:
            self.performance_metrics.tool_feedback_count += 1

        # Update satisfaction score
        self._update_satisfaction_score(feedback_entry)

        # Learn from feedback
        self._learn_from_feedback(feedback_entry)

    def _update_satisfaction_score(self, feedback_entry: FeedbackEntry):
        """Update overall satisfaction score based on feedback"""

        # Get weight for this feedback type
        weight = self.learning_weights.get(feedback_entry.feedback_type, 0.0)

        # Apply confidence scaling
        weighted_score = weight * feedback_entry.confidence

        # Update running average (with decay)
        alpha = 0.1  # Learning rate
        self.performance_metrics.overall_satisfaction_score = (
            (1 - alpha) * self.performance_metrics.overall_satisfaction_score +
            alpha * weighted_score
        )

        # Track trend
        self.performance_metrics.response_accuracy_trend.append(weighted_score)
        if len(self.performance_metrics.response_accuracy_trend) > 50:
            self.performance_metrics.response_accuracy_trend = self.performance_metrics.response_accuracy_trend[-25:]

    def _learn_from_feedback(self, feedback_entry: FeedbackEntry):
        """Extract learning insights from feedback"""

        feedback_type = feedback_entry.feedback_type

        # Learn from different feedback types
        if feedback_type == FeedbackType.NEGATIVE_DENIAL:
            # Record patterns that led to wrong answers
            self._analyze_failure_pattern(feedback_entry)

        elif feedback_type == FeedbackType.EVIDENCE_REQUEST:
            # Record claims that needed evidence
            self.rag_insights['evidence_gaps'].append({
                'timestamp': feedback_entry.timestamp,
                'context': feedback_entry.context_window[-1] if feedback_entry.context_window else '',
                'tools_used': feedback_entry.tools_used,
                'rag_active': feedback_entry.rag_active
            })

        elif feedback_type == FeedbackType.TOOL_FEEDBACK:
            # Record tool selection issues
            self.rag_insights['tool_mismatches'].append({
                'timestamp': feedback_entry.timestamp,
                'tools_used': feedback_entry.tools_used,
                'user_suggestion': feedback_entry.user_input,
                'context': feedback_entry.context_window[-1] if feedback_entry.context_window else ''
            })

        elif feedback_type == FeedbackType.CLARIFICATION_REQUEST:
            # Record clarity issues
            self.rag_insights['clarity_issues'].append({
                'timestamp': feedback_entry.timestamp,
                'unclear_response': feedback_entry.context_window[-1] if feedback_entry.context_window else '',
                'clarification_request': feedback_entry.user_input
            })

    def _analyze_failure_pattern(self, feedback_entry: FeedbackEntry):
        """Analyze what led to a negative response"""

        if feedback_entry.context_window:
            last_context = feedback_entry.context_window[-1]

            # Extract response from context (could be dict or string)
            if isinstance(last_context, dict):
                last_response = last_context.get('assistant_response', '')
            else:
                last_response = str(last_context)

            # Look for patterns in failed responses
            failure_indicators = {
                'high_confidence_words': ['definitely', 'certainly', 'always', 'never'],
                'absolute_statements': ['all', 'every', 'none', 'impossible'],
                'unsupported_claims': ['studies show', 'research indicates', 'experts say'],
            }

            failure_pattern = {
                'timestamp': feedback_entry.timestamp,
                'failed_response': last_response,
                'rag_active': feedback_entry.rag_active,
                'tools_used': feedback_entry.tools_used,
                'indicators_found': []
            }

            # Check for problematic patterns
            if last_response:
                for indicator_type, phrases in failure_indicators.items():
                    found_phrases = [phrase for phrase in phrases if phrase in last_response.lower()]
                    if found_phrases:
                        failure_pattern['indicators_found'].extend(found_phrases)

            self.rag_insights['high_confidence_errors'].append(failure_pattern)

    def get_rag_optimization_recommendations(self) -> Dict[str, Any]:
        """Generate recommendations for RAG optimization based on feedback"""

        recommendations = {
            'overall_score': self.performance_metrics.overall_satisfaction_score,
            'feedback_summary': self._get_feedback_summary(),
            'specific_improvements': [],
            'pattern_insights': {},
            'priority_actions': []
        }

        # Analyze evidence gaps
        if len(self.rag_insights['evidence_gaps']) >= 3:
            recommendations['specific_improvements'].append({
                'issue': 'Frequent evidence requests',
                'count': len(self.rag_insights['evidence_gaps']),
                'recommendation': 'Include more source citations and evidence in responses',
                'priority': 'high'
            })
            recommendations['priority_actions'].append('Enable automatic citation inclusion')

        # Analyze tool mismatches
        if len(self.rag_insights['tool_mismatches']) >= 2:
            tool_issues = defaultdict(int)
            for mismatch in self.rag_insights['tool_mismatches']:
                for tool in mismatch['tools_used']:
                    tool_issues[tool] += 1

            recommendations['specific_improvements'].append({
                'issue': 'Tool selection problems',
                'problematic_tools': dict(tool_issues),
                'recommendation': 'Improve tool selection logic and context awareness',
                'priority': 'medium'
            })

        # Analyze accuracy challenges
        if self.performance_metrics.accuracy_challenges > 0:
            accuracy_rate = (
                self.performance_metrics.positive_feedback_count /
                max(1, self.performance_metrics.total_interactions)
            )
            if accuracy_rate < 0.7:
                recommendations['priority_actions'].append('Review confidence calibration')

        # Analyze satisfaction trend
        if len(self.performance_metrics.response_accuracy_trend) >= 10:
            recent_trend = self.performance_metrics.response_accuracy_trend[-10:]
            recent_avg = sum(recent_trend[-5:]) / 5
            earlier_avg = sum(recent_trend[:5]) / 5
            trend_direction = recent_avg - earlier_avg

            recommendations['pattern_insights']['satisfaction_trend'] = {
                'direction': 'improving' if trend_direction > 0.1 else 'declining' if trend_direction < -0.1 else 'stable',
                'recent_average': sum(recent_trend) / len(recent_trend),
                'recommendation': 'Continue current approach' if trend_direction >= 0 else 'Review recent changes'
            }

        return recommendations

    def _get_feedback_summary(self) -> Dict[str, Any]:
        """Get summary of feedback received"""

        total = max(1, len(self.feedback_history))

        return {
            'total_feedback_entries': total,
            'positive_rate': self.performance_metrics.positive_feedback_count / total,
            'negative_rate': self.performance_metrics.negative_feedback_count / total,
            'evidence_request_rate': self.performance_metrics.evidence_requests / total,
            'accuracy_challenge_rate': self.performance_metrics.accuracy_challenges / total,
            'rag_usage_rate': self.performance_metrics.rag_active_interactions / max(1, self.performance_metrics.total_interactions)
        }

    def add_interaction_context(self, user_input: str, assistant_response: str,
                              rag_active: bool, tools_used: List[str]):
        """Add interaction to context for feedback analysis"""

        self.interaction_context.append({
            'timestamp': time.time(),
            'user_input': user_input,
            'assistant_response': assistant_response,
            'rag_active': rag_active,
            'tools_used': tools_used
        })

    def should_request_feedback(self) -> bool:
        """Determine if we should proactively ask for feedback"""

        # Request feedback if we haven't received any in a while
        if len(self.feedback_history) == 0 and self.performance_metrics.total_interactions > 10:
            return True

        # Request feedback if satisfaction is declining
        if (len(self.performance_metrics.response_accuracy_trend) >= 5 and
            sum(self.performance_metrics.response_accuracy_trend[-3:]) / 3 < -0.3):
            return True

        # Request feedback periodically
        if self.performance_metrics.total_interactions % 50 == 0:
            return True

        return False

    def get_performance_dashboard(self) -> str:
        """Generate a performance dashboard string"""

        metrics = self.performance_metrics
        recommendations = self.get_rag_optimization_recommendations()

        dashboard = f"""
🎯 RAG Feedback Performance Dashboard

📊 Overall Metrics:
  • Total Interactions: {metrics.total_interactions}
  • RAG Active Rate: {metrics.rag_active_interactions / max(1, metrics.total_interactions) * 100:.1f}%
  • Satisfaction Score: {metrics.overall_satisfaction_score:.2f}
  • Positive Feedback: {metrics.positive_feedback_count} ({metrics.positive_feedback_count / max(1, len(self.feedback_history)) * 100:.1f}%)
  • Negative Feedback: {metrics.negative_feedback_count} ({metrics.negative_feedback_count / max(1, len(self.feedback_history)) * 100:.1f}%)

🚨 Learning Insights:
  • Evidence Requests: {metrics.evidence_requests} (need more citations)
  • Accuracy Challenges: {metrics.accuracy_challenges} (confidence issues)
  • Tool Feedback: {metrics.tool_feedback_count} (selection problems)

🎯 Top Recommendations:
"""

        for action in recommendations['priority_actions'][:3]:
            dashboard += f"  • {action}\n"

        return dashboard


# Testing function
def test_rag_feedback_engine():
    """Test the RAG feedback learning engine"""

    print("🧪 Testing RAG Feedback Engine\n")

    # Initialize engine
    feedback_engine = RAGFeedbackEngine()

    # Simulate interaction sequence
    initial_interaction = ("What is the capital of France?", "The capital of France is Paris, which has been the capital since 987 AD.", True, ['web_search'])

    test_feedback_inputs = [
        ("thanks", {}),  # Positive confirmation
        ("are you sure about 987 AD?", {}),  # Accuracy challenge
        ("show me the source", {}),  # Evidence request
        ("that's wrong", {}),  # Negative denial
        ("use a different tool next time", {}),  # Tool feedback
        ("good answer", {}),  # Positive confirmation
        ("I don't understand", {}),  # Clarification request
    ]

    print("📋 Processing Feedback Sequence:")
    print("-" * 60)

    # Set up initial context
    user_input, assistant_response, rag_active, tools_used = initial_interaction
    feedback_engine.add_interaction_context(user_input, assistant_response, rag_active, tools_used)
    print(f"🤖 System: {assistant_response}")
    print("-" * 60)

    for i, (user_input, context) in enumerate(test_feedback_inputs):

        # Analyze feedback
        context['rag_active'] = i % 3 == 0  # Simulate RAG being active sometimes
        context['tools_used'] = ['web_search'] if context.get('rag_active') else []

        feedback_entry = feedback_engine.analyze_user_feedback(user_input, context)

        if feedback_entry:
            print(f"👤 User: {user_input}")
            print(f"📈 Feedback Type: {feedback_entry.feedback_type.value}")
            print(f"🎯 Confidence: {feedback_entry.confidence:.2f}")
            print(f"🔧 RAG Active: {feedback_entry.rag_active}")
            print("-" * 60)
        else:
            print(f"👤 User: {user_input}")
            print(f"❌ No feedback detected")
            print("-" * 60)

    # Generate recommendations
    print("\n🎯 RAG Optimization Recommendations:")
    recommendations = feedback_engine.get_rag_optimization_recommendations()
    print(f"Overall Score: {recommendations['overall_score']:.2f}")
    print(f"Total Feedback Entries: {recommendations['feedback_summary']['total_feedback_entries']}")
    print(f"Positive Rate: {recommendations['feedback_summary']['positive_rate']:.2f}")
    print(f"Negative Rate: {recommendations['feedback_summary']['negative_rate']:.2f}")

    if recommendations['priority_actions']:
        print("\n🚨 Priority Actions:")
        for action in recommendations['priority_actions']:
            print(f"  • {action}")

    # Show performance dashboard
    print(feedback_engine.get_performance_dashboard())


if __name__ == "__main__":
    test_rag_feedback_engine()